module calendar
(
    input CLK,
    input RST,
    output [5:0] Hours,
    output [5:0] Mins,
    output [5:0] Secs
);

    parameter MAX_SECONDS = 59;
    parameter MAX_MINUTES = 59;
    parameter MAX_HOURS = 23;

    reg [5:0] Secs_reg, Mins_reg, Hours_reg;

    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            Secs_reg <= 0;
        end else if (Secs_reg == MAX_SECONDS) begin
            Secs_reg <= 0;
        end else begin
            Secs_reg <= Secs_reg + 1;
        end
    end

    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            Mins_reg <= 0;
        end else if (Mins_reg == MAX_MINUTES && Secs_reg == MAX_SECONDS) begin
            Mins_reg <= 0;
        end else if (Secs_reg == MAX_SECONDS) begin
            Mins_reg <= Mins_reg + 1;
        end else begin
            Mins_reg <= Mins_reg;
        end
    end

    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            Hours_reg <= 0;
        end else if (Hours_reg == MAX_HOURS && Mins_reg == MAX_MINUTES && Secs_reg == MAX_SECONDS) begin
            Hours_reg <= 0;
        end else if (Mins_reg == MAX_MINUTES && Secs_reg == MAX_SECONDS) begin
            Hours_reg <= Hours_reg + 1;
        end else begin
            Hours_reg <= Hours_reg;
        end
    end

    assign Secs = Secs_reg;
    assign Mins = Mins_reg;
    assign Hours = Hours_reg;
endmodule
